// ValidateToken validates the service mesh token and returns the identity
func (tv *TokenValidator) ValidateToken(token string) (*ServiceIdentity, error) {
	// Sanitize input: reject empty or excessively long tokens
	if len(token) == 0 {
		return nil, errors.New("empty token")
	}
	if len(token) > 4096 {
		return nil, errors.New("token exceeds maximum length")
	}

	// Check revocation list
	if tv.isTokenRevoked(token) {
		return nil, errors.New("token has been revoked")
	}

	// Token format: <service_name>.<namespace>.<timestamp_hex>.<hmac_hex>
	parts := strings.SplitN(token, ".", 4)
	if len(parts) != 4 {
		return nil, errors.New("invalid token format")
	}

	serviceName := parts[0]
	namespace := parts[1]
	timestampHex := parts[2]
	providedMAC := parts[3]

	// Validate service name and namespace contain only allowed characters
	if !isValidIdentifier(serviceName) || !isValidIdentifier(namespace) {
		return nil, errors.New("invalid characters in token fields")
	}

	// Validate timestamp
	timestampBytes, err := hex.DecodeString(timestampHex)
	if err != nil || len(timestampBytes) != 8 {
		return nil, errors.New("invalid timestamp in token")
	}

	var timestamp int64
	for i := 0; i < 8; i++ {
		timestamp = (timestamp << 8) | int64(timestampBytes[i])
	}

	tokenTime := time.Unix(timestamp, 0)
	now := time.Now()

	// Reject tokens from the future (with small clock skew allowance)
	if tokenTime.After(now.Add(30 * time.Second)) {
		return nil, errors.New("token timestamp is in the future")
	}

	// Reject expired tokens (1 hour validity)
	if now.Sub(tokenTime) > 1*time.Hour {
		return nil, errors.New("token has expired")
	}

	// Verify HMAC
	message := fmt.Sprintf("%s.%s.%s", serviceName, namespace, timestampHex)
	mac := hmac.New(sha256.New, tv.hmacSecret)
	mac.Write([]byte(message))
	expectedMAC := hex.EncodeToString(mac.Sum(nil))

	// Constant-time comparison to prevent timing attacks
	if subtle.ConstantTimeCompare([]byte(providedMAC), []byte(expectedMAC)) != 1 {
		return nil, errors.New("invalid token signature")
	}

	// Check service is in the allowlist
	tv.mu.RLock()
	permissions, allowed := tv.allowedServices[serviceName]
	tv.mu.RUnlock()

	if !allowed {
		return nil, fmt.Errorf("service not in allowlist")
	}

	return &ServiceIdentity{
		ServiceName: serviceName,
		Namespace:   namespace,
		Permissions: permissions,
		ExpiresAt:   tokenTime.Add(1 * time.Hour),
	}, nil
}

// isValidIdentifier checks that a string contains only alphanumeric characters and hyphens
func isValidIdentifier(s string) bool {
	if len(s) == 0 || len(s) > 253 {
		return false
	}
	for _, c := range s {
		if !((c >= 'a' && c <= 'z') || (c >= '0' && c <= '9') || c == '-') {
			return false
		}
	}
	// Must not start or end with hyphen
	if s[0] == '-' || s[len(s)-1] == '-' {
		return false
	}
	return true
}

